use GuzzleHttp\Client;
use GuzzleHttp\Exception\RequestException;
use GuzzleHttp\Handler\MockHandler;
use GuzzleHttp\HandlerStack;
use GuzzleHttp\Psr7\Response;
use PHPUnit\Framework\TestCase;

class ElibertyBookingHandlerTest extends TestCase {
    public function testItShouldGetDaysAvailabilityWithNoRedisCache() {
        // Setup mocks
        $this->apiHelper = $this->createMock(ApiHelper::class);
        $this->redisCache = $this->createMock(RedisCache::class);
        $this->restFactory = $this->createMock(ClientFactory::class);

        // Mock API response
        $mock = new MockHandler([
            new Response(200, ['content-type' => 'application/json'], json_encode([]))
        ]);

        // Inject mock into handler stack
        $handlerStack = HandlerStack::create($mock);
        $client = new Client(['handler' => $handlerStack]);

        $this->restFactory->method('getClient')->willReturn($client);

        // Setup expectations
        $this->redisCache->expects($this->once())->method('set');
        $this->apiHelper->method('getListOfDays')->willReturn(['2020-12-01']);

        // Execute
        $handler = new ElibertyBookingHandler($this->restFactory, $this->apiHelper, $this->redisCache, $this->em);
        $result = $handler->getDaysAvailability($this->product);

        $this->assertEquals(['2020-12-01'], $result);
    }
}
```

