114→    {
115→        $phone = $order->getPhone();
116→
117→        if (null === $externalBooking->getAuthorPhone() && null !== $order->getDatumcustom('mobile')) {
118→            $phone = $order->getDatumcustom('mobile');
119→        }
120→
121→        // Replace booker phone number with mobile if mobile was set
122→        if (null !== $order->getMobile()) {
123→            $phone = $order->getMobile();
124→        }
125→
126→        return $phone;
127→    }
