 34→    public function getListOfDays(array $bookingDays): array
 35→    {
 36→        $days = [];
 37→
 38→        if (0 !== \count($bookingDays) && !\array_key_exists('error', $bookingDays)) {
 39→            foreach ($bookingDays as $bookingDay) {
 40→                if (!\in_array($bookingDay['date'], $days)) {
 41→                    $days[] = $bookingDay['date'];
 42→                }
 43→            }
 44→        }
 45→
 46→        return $days;
 47→    }
