 49→    /**
 50→     * @param array $bookingActivites
 51→     *
 52→     * @return ArrayCollection<SubContingent>
 53→     *
 54→     * @throws \Exception
 55→     */
 56→    public function getSubContingents(array $bookingActivites): ArrayCollection
 57→    {
 58→        $list = new ArrayCollection();
 59→
 60→        foreach ($bookingActivites as $bookingActivity) {
 61→            $subContingent = $this->serializeSubContingentResponse($bookingActivity);
 62→            $list->add($subContingent);
 63→        }
 64→
 65→        return $list;
 66→    }
