 68→    /**
 69→     * @param array $response
 70→     *
 71→     * @return SubContingent
 72→     *
 73→     * @throws \Exception
 74→     */
 75→    public function serializeSubContingentResponse(array $response): SubContingent
 76→    {
 77→        $webinstance = $this->getWebinstance();
 78→
 79→        $subContingent = $this->em->getRepository(SubContingent::class)->findOneBy([
 80→            'externalId'  => $response['id'],
 81→            'webinstance' => $webinstance,
 82→        ]);
 83→
 84→        // Create object SubContingent if $subContingent not exists or update it if exists
 85→        if (null === $subContingent) {
 86→            $subContingent = new SubContingent();
 87→        }
 88→
 89→        $subContingent->setLabel($response['label'])
 90→                ->setDailyBooking($response['dailyBooking'])
 91→                ->setDate(new \DateTime($response['date']))
 92→                ->setExternalId($response['id'])
 93→                ->setLabel($response['label'])
 94→                ->setQuotaAvailable($response['quotaAvailablePublic'] - $response['quotaInUsePublic'])
 95→                ->setQuotaInUse($response['quotaInUsePublic'])
 96→                ->setType(ExternalBookingProvider::ELIBERTY_BOOKING)
 97→                ->setLimitQuotaOrderVel($response['limitQuotaOrderPublicVel'])
 98→                ->setSalesClosedAt(new \DateTime($response['closedAt']))
 99→                ->setPosition($response['position']);
100→
101→        if (isset($response['isQuotaUnlimitedForPublic'])) {
102→            $subContingent->setQuotaUnlimited((bool) $response['isQuotaUnlimitedForPublic']);
103→        }
104→
105→        if (isset($response['quotaUnlimitedForPublic'])) {
106→            $subContingent->setQuotaUnlimited((bool) $response['quotaUnlimitedForPublic']);
107→        }
108→
109→        $subContingent->setWebinstance($webinstance);
110→
111→        return $subContingent;
112→    }
