114→    /**
115→     * @param array                $response
116→     * @param SubContingent|null   $subContingent
117→     * @param ExternalBooking|null $externalBooking
118→     *
119→     * @return ExternalBooking
120→     *
121→     * @throws \Exception
122→     */
123→    public function serializeExternalBookingResponse(array $response, SubContingent $subContingent = null, ExternalBooking $externalBooking = null): ExternalBooking
124→    {
125→        // Create object ExternalBooking if $externalBooking not exists or update it if exists
126→        if (null === $externalBooking) {
127→            $externalBooking = new ExternalBooking();
128→
129→            if (null !== $subContingent) {
130→                $externalBooking->setSubContingent($subContingent);
131→            }
132→        }
133→
134→        $status = 'init'      === $response['orderState'] ? ExternalBookingState::INIT : null;
135→        $status = 'cart'      === $response['orderState'] ? ExternalBookingState::CART : $status;
136→        $status = 'confirmed' === $response['orderState'] ? ExternalBookingState::CONFIRMED : $status;
137→        $status = 'cancelled' === $response['orderState'] ? ExternalBookingState::CANCELLED : $status;
138→
139→        $externalBooking->setExternalId($response['id'] ?? $externalBooking->getExternalId())
140→                ->setType(ExternalBookingProvider::ELIBERTY_BOOKING)
141→                ->setExternalReference($response['bookingReference'])
142→                ->setLabel($response['unit']['resource']['label'])
143→                ->setStatus($status)
144→                ->setCount($response['count'])
145→                ->setWebinstance($this->getWebinstance())
146→                ->setAuthorLocale('fr_FR' === $response['bookerLocale'] ? 'fr' : 'en')
147→                ->setAuthorFirstname($response['bookerFirstname'])
148→                ->setAuthorLastname($response['bookerLastname'])
149→                ->setAuthorMail($response['bookerMail'])
150→                ->setAuthorPhone($response['bookerPhone']);
151→
152→        $subContingent = $this->serializeSubContingentResponse($response['unit']);
153→        $externalBooking->setSubContingent($subContingent);
154→
155→        return $externalBooking;
156→    }
