195→    {
196→        return [
197→            'order' => [
198→                'externalReference' => StringUtils::genUuid(),
199→                'bookingType'       => self::BOOKING_TYPE_PUBLIC,
200→                'unit'              => $subContingentData->getSubContingentId(),
201→                'count'             => $subContingentData->getQty(),
202→                'bookerLocale'      => str_replace('fr', 'fr_FR', $order->getLocale()),
203→                'bookerFirstname'   => ExternalBooking::DEFAULT_NAME,
