210→    public function getParamSynchronizeBooking(Order $order, ExternalBooking $externalBooking): array
211→    {
212→        $orderState   = ($order->isConfirmed() ? self::BOOKING_ORDERSTATE_CONFIRMED : self::BOOKING_ORDERSTATE_CART);
213→        $items        = $order->getItemsWithExternalBookings();
214→        $bookingItems = [];
215→
216→        foreach ($items as $item) {
217→            if ($item->getDatum('externalBookingId') === $externalBooking->getExternalId()) {
218→                $bookingItems[] = [
219→                    'cardNumber' => $item->getCardNumber(),
220→                    'lastname'   => $item->getLastname(),
221→                    'firstname'  => $item->getFirstname(),
222→                    'birthdate'  => null !== $item->getBirthdate() ? $item->getBirthdate()->format('Y-m-d\TH:i:s') : null,
223→                    'personType' => $item->getConscatShortName(),
224→                ];
225→            }
226→        }
227→
228→        return [
229→            'order' => [
230→                'externalReference' => $order->getId(),
231→                'count'             => \count($bookingItems),
232→                'bookerLocale'      => 'fr' === $order->getLocale() ? 'fr_FR' : $order->getLocale(),
233→                'bookerFirstname'   => $this->getBookerName('firstname', $order, $externalBooking),
234→                'bookerLastname'    => $this->getBookerName('lastname', $order, $externalBooking),
235→                'bookerPhone'       => $this->getBookerPhone($order, $externalBooking),
236→                'orderState'        => $orderState,
237→                'bookerMail'        => $order->getEmail(),
238→                'orderItems'        => $bookingItems,
239→                'totalPrice'        => $order->getTotal(),
240→            ],
241→        ];
242→    }
