245→    {
246→        return [
247→            'order' => [
248→                'orderState'   => self::BOOKING_ORDERSTATE_CONFIRMED,
249→                'bookerMail'   => $order->getEmail(),
250→                'totalPrice'   => $order->getTotal(),
251→                'bookerLocale' => 'fr' === $order->getLocale() ? 'fr_FR' : $order->getLocale(),
252→            ],
253→        ];
254→    }
