 * @param $name
 * @param $arguments
 *
 * @return array|mixed|null
 */
public function __call($name, $arguments)
{
    $exposedProperties = [
        'lastname', 'firstname', 'birthdate', 'externalid', 'gender', 'language',
        'phone', 'mobile', 'optin', 'partneroptin', 'documents', 'cashdeskid',
        'externalreference', 'title', 'externalguid',
    ];

    $key  = null;
    $name = strtolower($name);

    if ('get' === substr($name, 0, 3)) {
        $name = substr($name, 3);
    }

    if (\in_array($name, $exposedProperties, true)) {
        $key = $name;
    }

    if (null !== $key) {
        $accessor = new PropertyAccessor();
        if (LoginModeType::ACCOUNTLESS !== $this->loginMode && null !== $this->getContact()) {
            $datum = $accessor->getValue($this->getContact(), $key);
        } else {
            $datum = 0 === \count($this->contactjson)
                ? $this->getDatum($key)
                : $this->getContactDatum($key);
        }
        if (\is_array($datum) && !empty($datum['date']) && \is_string($datum['date'])) {
            $datum = new \DateTime($datum['date'], new \DateTimeZone($datum['timezone']));
        }

        return $datum;
    }

