        ];
    }

    /**
     * Resolves the booking-detail payload at confirm time, when we no longer have a
     * SubContingentData carrier. Falls back to the first matching Order item.
     *
     * @return array<string, mixed>
     */
    private function buildBookingDetailForExternalBooking(Order $order, ExternalBooking $externalBooking): array
    {
        $productName = (string) $externalBooking->getLabel();
        $productId   = $externalBooking->getExternalId();

        foreach ($order->getItemsWithExternalBookings() as $item) {
            if ($item->getDatum('externalBookingId') !== $externalBooking->getExternalId()) {
                continue;
            }
            $product = $item->getProduct();
            if (null !== $product) {
                $productName = (string) $product->getName();
                $productId   = (string) ($product->getCode() ?? (string) $product->getId());
            }
            break;
        }

        return [
            'productName' => $productName,
            'productId'   => $productId,
            'pricePaid'   => (int) round(((float) $order->getTotal()) * 100),
            'currency'    => self::CURRENCY_EUR,
            'orderDate'   => (new \DateTime('today'))->format('Y-m-d'),
            'origin'      => self::ORIGIN_ESHOP,
        ];
    }
}

